import shutil

# Root directory of the framework
BASE_DIR = r"c:\Users\ronyc\Desktop\MDL Ynor Principal Investigatorure\MDL_Ynor_Framework"

# Files to synchronize (Source -> Targets)
# We choose the best/most complete version as source
SYNC_PLAN = [
    {
        "src": os.path.join(BASE_DIR, "_01_THEORY_AND_PAPERS", "MDL_YNOR_TECHNICAL_SPECIFICATIONS.md"),
        "targets": [
            os.path.join(BASE_DIR, "_10_YNOR_AI_KNOWLEDGE_BASE_SOURCES", "MDL_YNOR_TECHNICAL_SPECIFICATIONS.md"),
            os.path.join(BASE_DIR, "MDL_YNOR_GPT_KNOWLEDGE", "MDL_YNOR_TECHNICAL_SPECIFICATIONS.md")
        ]
    },
    {
        "src": os.path.join(BASE_DIR, "_01_THEORY_AND_PAPERS", "MDL_YNOR_SCIENTIFIC_WHITE_PAPER.md"),
        "targets": [
            os.path.join(BASE_DIR, "_10_YNOR_AI_KNOWLEDGE_BASE_SOURCES", "MDL_YNOR_SCIENTIFIC_WHITE_PAPER.md"),
            os.path.join(BASE_DIR, "MDL_GPT_KNOWLEDGE_PRODUCTION", "MDL_YNOR_SCIENTIFIC_WHITE_PAPER.md")
        ]
    },
    {
        "src": os.path.join(BASE_DIR, "_PREUVES_ET_RAPPORTS", "BENCHMARK_ULTRA_HARDCORE_ULTIMATE_10_10.md"),
        "targets": [
            os.path.join(BASE_DIR, "_01_THEORY_AND_PAPERS", "BENCHMARK_ULTRA_HARDCORE_ULTIMATE_10_10.md"),
            os.path.join(BASE_DIR, "_10_YNOR_AI_KNOWLEDGE_BASE_SOURCES", "BENCHMARK_ULTRA_HARDCORE_ULTIMATE_10_10.md")
        ]
    }
]

def deep_sync():
    print("--- LANCEMENT DE LA SYNCHRONISATION PROFONDE DU CORPUS ---")
    for task in SYNC_PLAN:
        src = task["src"]
        if not os.path.exists(src):
            print(f" Source manquante : {src}")
            continue

        for target in task["targets"]:
            os.makedirs(os.path.dirname(target), exist_ok=True)
            shutil.copy2(src, target)
            print(f"OK Synchronise : {os.path.relpath(target, BASE_DIR)}")

    print("\n--- SYNCHRONISATION TERMINE ---")

if __name__ == "__main__":
    deep_sync()

import os
import json
import hashlib

FRAMEWORK_DIR = r"c:\Users\ronyc\Desktop\MDL Ynor Principal Investigatorure\MDL_Ynor_Framework"
JSON_FILE = r"c:\Users\ronyc\Desktop\MDL Ynor Principal Investigatorure\MDL_Ynor_Framework\MDL_YNOR_GPT_KNOWLEDGE\mdl_global_knowledge.json"

def estimate_tokens(text):
    return len(text) // 4

def get_file_hash(filepath):
    try:
        with open(filepath, "rb") as f:
            return hashlib.md5(f.read()).hexdigest()
    except Exception:
        return ""

def update_json():
    current_meta = {
        "version": "2.2.0-PROD",
        "description": "Auto-Generated Knowledge Base with Geomagnetism and WMM Integration",
        "last_updated": "2026-03-24",
        "security_protocols": {} 
    }

    if os.path.exists(JSON_FILE) and os.path.getsize(JSON_FILE) > 0:
        with open(JSON_FILE, "r", encoding="utf-8") as f:
            data = json.load(f)
        # Update existing meta while preserving security protocols
        existing_meta = data.get("system_meta", {})
        current_meta["security_protocols"] = existing_meta.get("security_protocols", {})
        data["system_meta"] = current_meta
    else:
        data = {
            "system_meta": current_meta,
            "knowledge_nodes": []
        }

    # Use filepath + filename as unique identifier for nodes
    # If the JSON doesn't have it, we might need to map by file/folder
    # Map existing nodes by (folder, file) and determine the next ID
    existing_nodes = {}
    max_id_num = -1
    for node in data.get("knowledge_nodes", []):
        key = (node.get("folder"), node.get("file"))
        existing_nodes[key] = node
        # Extract numeric part of id (e.g., node_fw_042 -> 42)
        try:
            id_num = int(node.get("id", "node_fw_0").split("_")[-1])
            if id_num > max_id_num:
                max_id_num = id_num
        except (ValueError, IndexError):
            pass

    next_id_num = max_id_num + 1
    new_count = 0
    updated_count = 0
    seen_keys = set()

